Promise.resolve(5)
  .then(x => {
    console.log('x:', x);
    return x + 2;
  })
  .then(y => {
    console.log('y:', y);
    throw new Error('Boom!');
  })
  .then(z => {
    console.log('z:', z); // skipped
  })
  .catch(err => {
    console.log('Caught:', err.message);
  });
